// Import of required libraries
import { test } from '@playwright/test';
import { newSkyrampPlaywrightPage, expect } from '@skyramp/skyramp';

const pageTimeout = 15000;

test('testUi', async ({ page }) => {
    test.setTimeout(165000);

    // set default timeout for all locator/page actions in this test
    page.setDefaultTimeout(pageTimeout);
    // Wrap playwright page with Skyramp page
    page = newSkyrampPlaywrightPage(page);

    const pageErrors: Error[] = [];
    page.on('pageerror', (err) => pageErrors.push(err));

    await page.goto("http://localhost:8055/admin/content/+wizard");
    await page.getByRole("textbox", { name: "Email" }).fill("admin@example.com");
    await page.getByRole("textbox", { name: "Password" }).fill("admin");
    await page.getByRole("button", { name: "Sign In" }).click();
    await page.locator('[data-test="wizard-name-input"]').fill("back_nav_test");
    await page.getByRole("button", { name: "Next" }).click();
    // Step 2: fill field but click Back without clicking Next — field is NOT committed to store
    await page.locator('[data-test="wizard-fields-name-0"]').fill("description");
    await page.getByRole("button", { name: "Back" }).click();
    // Back to step 1 — collection name must be preserved
    await expect(page.locator('[data-test="wizard-name-input"]')).toHaveValue('back_nav_test');
    // Re-enter step 2 and this time click Next to commit field to Pinia store
    await page.getByRole("button", { name: "Next" }).click();
    await page.locator('[data-test="wizard-fields-name-0"]').fill("description");
    await page.getByRole("button", { name: "Next" }).click();
    // Now on step 3 (relations) — click Back to return to step 2
    await page.getByRole("button", { name: "Back" }).click();
    // Step 2 must show the committed field value from Pinia store
    await expect(page.locator('[data-test="wizard-fields-name-0"]')).toHaveValue('description');

    await expect(pageErrors).toHaveLength(0);
});
